import React from "react";
import { Flex } from "../../_compat";
import type { IAlertComponent } from "@lmb-it/kitsconcerto-types";
import {Text, Icon} from "../../_compat";
import { useKitsTheme } from "../../contexts/Theme";

import {
    AlertTriangle,
    CheckCircle2,
    Info,
    CircleX
} from "lucide-react-native";

const icons: Record<string, any> = {
    error: CircleX,
    success: CheckCircle2,
    warning: AlertTriangle,
    info: Info,
};

const Alert: React.FC<IAlertComponent> = ({
                                          status = "info",
                                          variant = "subtle",
                                          children,
                                          className,
                                          ...props
                                      }) => {
    const { resolveToken } = useKitsTheme();
    const primary = resolveToken('primary');

    const statusColors: Record<string, string> = {
        error: resolveToken('red.500'),
        success: resolveToken('green.500'),
        warning: resolveToken('yellow.500'),
        info: resolveToken('blue.500'),
        brand: primary,
    };

    const color = statusColors[status!];
    let bg = "transparent";
    let border:any = undefined;

    if (variant === "subtle") bg = `${color}22`;
    if (variant === "solid") bg = color;
    if (variant === "left-accent") border = { borderLeftWidth: 4, borderLeftColor: color };
    if (variant === "top-accent") border = { borderTopWidth: 4, borderTopColor: color };

    // Determine text color: white on solid, dark status color otherwise
    const textColor = variant === "solid" ? "#FFFFFF" : color;

    return (
        <Flex
            className={className}
            flexDirection="row"
            alignItems="center"
            gap={12}
            style={{
                padding: 12,
                borderRadius: 8,
                backgroundColor: bg,
                alignSelf: 'flex-start',
                ...(border ?? {}),
            }}
            {...props}
        >
            {typeof children === "string" ? (
                <Text style={{ color: textColor }}>{children}</Text>
            ) : (
                children
            )}
        </Flex>
    );
};

export const AlertIcon: React.FC<{ status: IAlertComponent["status"] }> = ({ status = "info" }) => {
    const { resolveToken, theme } = useKitsTheme();
    const primary = resolveToken('primary');

    if (status === 'brand' && theme.config.logo) return <>{theme.config.logo}</>;

    const statusColors: Record<string, string> = {
        error: resolveToken('red.500'),
        success: resolveToken('green.500'),
        warning: resolveToken('yellow.500'),
        info: resolveToken('blue.500'),
        brand: primary,
    };

    const IconComponent = icons[status!];
    const color = statusColors[status!];

    return (
        <Icon name={IconComponent} color={color} size="lg" />
    );
};

export const AlertTitle: React.FC<{ children: React.ReactNode; color?: string }> = ({ children, color }) => (
    <Text fontWeight="bold" style={color ? { color } : undefined}>{children}</Text>
);

export const AlertDescription: React.FC<{ children: React.ReactNode; color?: string }> = ({ children, color }) => (
    <Text size="sm" style={color ? { color } : undefined}>{children}</Text>
);

export default Alert;
